INSERT INTO scenarios (id, title, intro, skill_id, tt32_tag, steps, endings) VALUES ('SC01', 'Tình huống: Phản ứng truyền máu cấp', 'Bạn đang trực phòng hồi tỉnh. Bệnh nhân nữ 58 tuổi sau mổ cắt dạ dày, đang truyền 1 đơn vị KHC. Sau 10 phút truyền (~30mL), bệnh nhân đột ngột sốt 39.2°C, lạnh run, đau lưng vùng thắt lưng, tụt HA 85/50. SpO2 92%.', 'S5.2', '+', '[{"id": "s1", "prompt": "Hành động ĐẦU TIÊN của bạn là gì?", "options": [{"label": "Tăng tốc độ truyền để hết nhanh, giảm thời gian phơi nhiễm", "next": "bad1", "points": -20, "feedback": "❌ Sai nguyên tắc. Đây là phản ứng truyền máu cấp - tăng tốc sẽ làm tình trạng nặng thêm."}, {"label": "Ngừng truyền ngay, giữ đường truyền với NaCl 0.9%", "next": "s2", "points": 15, "feedback": "✓ Đúng. Đây là bước đầu tiên trong xử trí phản ứng truyền máu cấp."}, {"label": "Cho bệnh nhân uống paracetamol để hạ sốt", "next": "bad2", "points": -15, "feedback": "❌ Sai - hạ sốt không phải ưu tiên; cần xử trí phản ứng cấp trước."}]}, {"id": "s2", "prompt": "Sau khi ngừng truyền, bước tiếp theo?", "options": [{"label": "Báo bác sĩ ngay, theo dõi sát sinh hiệu mỗi 5 phút, lấy mẫu xét nghiệm", "next": "s3", "points": 15, "feedback": "✓ Đúng quy trình."}, {"label": "Đợi 15 phút xem có cải thiện", "next": "bad3", "points": -15, "feedback": "❌ Không nên trì hoãn - phản vệ/AHTR có thể tiến triển nhanh."}, {"label": "Tự ý truyền adrenalin", "next": "bad4", "points": -20, "feedback": "❌ Cần chỉ định bác sĩ; không tự ý dùng thuốc cấp cứu khi chưa có y lệnh trừ trường hợp phản vệ rõ rệt theo phác đồ."}]}, {"id": "s3", "prompt": "Cần bảo quản gì để truy xuất nguyên nhân phản ứng?", "options": [{"label": "Túi máu + bộ dây truyền + mẫu máu BN", "next": "end_good", "points": 20, "feedback": "✓ Hoàn hảo! Lưu ≥ 24h tại tủ riêng để xét nghiệm xác minh."}, {"label": "Chỉ túi máu", "next": "end_partial", "points": 5, "feedback": "⚠ Chưa đủ. Cần lưu cả bộ dây và mẫu máu BN."}, {"label": "Vứt hết để vệ sinh", "next": "end_bad", "points": -25, "feedback": "❌ Sai nghiêm trọng - vi phạm quy định truy xuất."}]}]'::jsonb, '{"end_good": {"title": "🎉 Xử trí xuất sắc!", "msg": "Bạn đã xử trí phản ứng truyền máu cấp đúng quy trình. +50 XP, badge ''Cấp cứu kịp thời'' tiến triển."}, "end_partial": {"title": "💪 Khá tốt", "msg": "Bạn xử trí đúng phần lớn nhưng cần ôn lại quy trình lưu mẫu sau phản ứng. +15 XP."}, "end_bad": {"title": "📚 Cần ôn lại", "msg": "Một số bước sai nghiêm trọng. Đề nghị xem lại Quy trình truyền máu & XTTBTM trước khi thực hành."}, "bad1": {"title": "❌ Sai nguyên tắc cốt lõi", "msg": "Trong mọi phản ứng truyền máu cấp, bước đầu là NGỪNG TRUYỀN. Tăng tốc làm tình trạng nặng thêm."}, "bad2": {"title": "❌ Sai thứ tự ưu tiên", "msg": "Hạ sốt không phải ưu tiên đầu tiên. Cần dừng tác nhân nghi ngờ trước."}, "bad3": {"title": "❌ Trì hoãn nguy hiểm", "msg": "Phản ứng truyền máu cấp có thể tiến triển thành DIC, suy thận - không nên đợi."}, "bad4": {"title": "❌ Vượt thẩm quyền", "msg": "Adrenalin cần chỉ định BS hoặc theo phác đồ phản vệ. ĐD không tự ý dùng."}}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenarios (id, title, intro, skill_id, tt32_tag, steps, endings) VALUES ('SC02', 'Tình huống: Khó thở sau rút NKQ', 'Bệnh nhân nam 42 tuổi vừa được rút NKQ tại phòng hồi tỉnh sau mổ cắt amidan. Sau 5 phút, BN khó thở, thở rít (stridor), co kéo cơ hô hấp phụ, SpO2 87% và đang giảm.', 'S3.4', '*', '[{"id": "s1", "prompt": "Đánh giá tình trạng - đây là gì?", "options": [{"label": "Tắc nghẽn đường thở do phù thanh quản", "next": "s2", "points": 15, "feedback": "✓ Đúng. Stridor + co kéo + tụt SpO2 là phù thanh quản cấp."}, {"label": "Cơn hen phế quản", "next": "bad1", "points": -10, "feedback": "❌ Hen có wheeze (rít) ở thì thở ra; phù thanh quản có stridor (rít) ở thì hít vào."}, {"label": "Lo âu sau mê", "next": "bad2", "points": -15, "feedback": "❌ SpO2 87% là dấu hiệu nguy hiểm thực thể, không phải lo âu."}]}, {"id": "s2", "prompt": "Bước xử trí tiếp theo phù hợp?", "options": [{"label": "Cho oxy mask 100%, gọi BS ngay, chuẩn bị bộ đặt NKQ và adrenalin khí dung", "next": "s3", "points": 15, "feedback": "✓ Hoàn hảo! Xử trí cấp cứu chuẩn."}, {"label": "Cho NB ngồi dậy đi lại nhẹ", "next": "bad3", "points": -20, "feedback": "❌ Tuyệt đối không! Đường thở chưa ổn định."}, {"label": "Cho ăn nhẹ để ''hồi sức''", "next": "bad4", "points": -25, "feedback": "❌ Cực kỳ nguy hiểm - có thể gây hít sặc."}]}, {"id": "s3", "prompt": "BS chỉ định adrenalin khí dung. Liều khởi đầu cho người lớn?", "options": [{"label": "Adrenalin 1mg pha NaCl 0.9% đủ 3-5 mL khí dung", "next": "end_good", "points": 20, "feedback": "✓ Liều chuẩn cho phù thanh quản người lớn."}, {"label": "Adrenalin 10 mg tiêm tĩnh mạch", "next": "end_bad", "points": -30, "feedback": "❌ Liều quá cao và đường dùng sai. Tử vong tiềm ẩn."}, {"label": "Adrenalin 0.1 mg dưới da", "next": "end_partial", "points": -5, "feedback": "⚠ Đường dùng và liều không phù hợp cho phù thanh quản."}]}]'::jsonb, '{"end_good": {"title": "🎉 Cứu sống bệnh nhân!", "msg": "Bạn xử trí phù thanh quản sau rút NKQ đúng phác đồ. +60 XP. Lưu ý: kỹ thuật rút NKQ là (*) chuyên khoa - chỉ ĐD ĐH+ có đào tạo bổ sung mới được xác nhận thực hiện."}, "end_partial": {"title": "💪 Hiểu nguyên tắc nhưng sai chi tiết", "msg": "Cần học lại liều và đường dùng adrenalin trong phù thanh quản. +20 XP."}, "end_bad": {"title": "⚠ Sai sót nghiêm trọng", "msg": "Liều thuốc cấp cứu sai có thể gây tử vong. Bắt buộc ôn lại trước khi thực hành."}, "bad1": {"title": "❌ Chẩn đoán sai", "msg": "Phân biệt stridor (đường thở trên) vs wheeze (đường thở dưới) là kỹ năng cơ bản."}, "bad2": {"title": "❌ Bỏ sót dấu hiệu nguy hiểm", "msg": "SpO2 87% với co kéo là cấp cứu - không phải lo âu."}, "bad3": {"title": "❌ Hành động nguy hiểm", "msg": "Vận động khi đường thở chưa ổn định có thể làm tình trạng xấu hơn."}, "bad4": {"title": "❌ Sai cơ bản", "msg": "Cho ăn khi đường thở chưa kiểm soát = nguy cơ hít sặc nặng."}}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenarios (id, title, intro, skill_id, tt32_tag, steps, endings) VALUES ('SC03', 'Tình huống: Sốc phản vệ sau kháng sinh', 'Bệnh nhân nam 35 tuổi đang truyền tĩnh mạch ceftriaxone trước phẫu thuật. Sau 3 phút, BN đột ngột phù mặt, khó thở, mày đay toàn thân, HA 70/40 mmHg, mạch 130 l/p, SpO2 89%.', 'S5.2', '+', '[{"id": "s1", "prompt": "Đây là tình trạng gì và ưu tiên xử trí?", "options": [{"label": "Phản vệ độ III - cần adrenalin tiêm bắp ngay", "next": "s2", "points": 15, "feedback": "✓ Đúng. Phù mặt + tụt HA + khó thở = phản vệ ≥ độ III. Adrenalin IM là xử trí đầu tay."}, {"label": "Tăng huyết áp - cho thuốc hạ áp", "next": "bad1", "points": -25, "feedback": "❌ HA 70/40 là TỤT HA, không phải tăng. Cho hạ áp = nguy hiểm tính mạng."}, {"label": "Lo âu - trấn an bệnh nhân", "next": "bad2", "points": -30, "feedback": "❌ Bỏ sót cấp cứu phản vệ - nguy cơ tử vong rất cao."}]}, {"id": "s2", "prompt": "Liều adrenalin tiêm bắp đầu tiên cho người lớn?", "options": [{"label": "0.5 mg (1:1000) tiêm bắp mặt ngoài đùi giữa", "next": "s3", "points": 15, "feedback": "✓ Đúng phác đồ Bộ Y tế."}, {"label": "1 mg tiêm tĩnh mạch chậm", "next": "bad3", "points": -30, "feedback": "❌ Tiêm tĩnh mạch chỉ khi ngừng tim hoặc theo BS hồi sức - rất nguy hiểm với liều này."}, {"label": "0.01 mg dưới da", "next": "bad4", "points": -15, "feedback": "❌ Liều quá thấp và đường dùng không phù hợp cho phản vệ ≥ III."}]}, {"id": "s3", "prompt": "Sau adrenalin, hành động đồng thời tiếp theo?", "options": [{"label": "Ngừng kháng sinh, gọi BS, oxy 100%, nâng cao chân, truyền dịch tinh thể", "next": "end_good", "points": 20, "feedback": "✓ Hoàn hảo - gói xử trí phản vệ đầy đủ."}, {"label": "Tiếp tục truyền kháng sinh để ''hết liều''", "next": "end_bad", "points": -30, "feedback": "❌ Sai cơ bản - phải ngừng tác nhân nghi ngờ ngay."}, {"label": "Cho ăn nhẹ để hồi sức", "next": "end_bad", "points": -25, "feedback": "❌ Tuyệt đối không cho ăn khi đường thở chưa ổn định."}]}]'::jsonb, '{"end_good": {"title": "🎉 Xử trí phản vệ kịp thời!", "msg": "Bạn xử trí phản vệ độ III đúng phác đồ Bộ Y tế. Adrenalin IM trong 5 phút đầu là yếu tố quyết định. +60 XP."}, "end_bad": {"title": "⚠ Sai sót nghiêm trọng", "msg": "Phản vệ độ III có nguy cơ tử vong. Cần ôn lại phác đồ phản vệ Bộ Y tế ngay."}, "bad1": {"title": "❌ Đọc sai dấu hiệu", "msg": "HA 70/40 là tụt HA, biểu hiện sốc - cho hạ áp sẽ làm tình trạng nặng thêm rất nhiều."}, "bad2": {"title": "❌ Bỏ sót cấp cứu", "msg": "Bộ ba phù mặt + tụt HA + khó thở là phản vệ - cấp cứu khẩn."}, "bad3": {"title": "❌ Đường dùng nguy hiểm", "msg": "Adrenalin TM 1mg gây loạn nhịp nặng. Phản vệ luôn dùng IM trước."}, "bad4": {"title": "❌ Liều dưới ngưỡng", "msg": "0.01 mg cho người lớn không đủ tác dụng."}}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenarios (id, title, intro, skill_id, tt32_tag, steps, endings) VALUES ('SC04', 'Tình huống: Ngừng tim trong phẫu thuật', 'Đang trong ca phẫu thuật ổ bụng. Monitor báo nhịp xoang chậm 30 l/p rồi đột ngột chuyển vô tâm thu (asystole). HA không đo được. SpO2 mất tín hiệu.', 'S5.1', '+', '[{"id": "s1", "prompt": "Hành động đầu tiên của ĐD trong kíp?", "options": [{"label": "Báo phẫu thuật viên/gây mê NGAY, bắt đầu ép tim", "next": "s2", "points": 15, "feedback": "✓ Đúng. Ngừng tim trong PT - bắt đầu CPR ngay, kíp phối hợp."}, {"label": "Đợi gây mê đánh giá", "next": "bad1", "points": -25, "feedback": "❌ Mất thời gian vàng - mỗi giây không CPR giảm cơ hội sống ~10%."}, {"label": "Tăng thuốc gây mê", "next": "bad2", "points": -30, "feedback": "❌ Sai cơ bản - ngừng tim cần CPR + epinephrine, không phải an thần."}]}, {"id": "s2", "prompt": "Trong CPR, tần số ép tim người lớn là?", "options": [{"label": "100-120/phút, độ sâu 5-6cm", "next": "s3", "points": 15, "feedback": "✓ Đúng theo AHA."}, {"label": "60-80/phút", "next": "bad3", "points": -15, "feedback": "❌ Tần số quá chậm - không hiệu quả tuần hoàn."}, {"label": "150/phút", "next": "bad4", "points": -15, "feedback": "❌ Quá nhanh - không đảm bảo đủ thời gian đổ đầy thất."}]}, {"id": "s3", "prompt": "Vô tâm thu - thuốc cấp cứu đầu tiên?", "options": [{"label": "Adrenalin 1 mg TM mỗi 3-5 phút + tiếp tục CPR", "next": "end_good", "points": 20, "feedback": "✓ Đúng. Vô tâm thu KHÔNG sốc điện - chỉ CPR + adrenalin."}, {"label": "Sốc điện 360 J", "next": "end_bad", "points": -25, "feedback": "❌ Sốc điện chỉ với VF/pVT, không dùng cho vô tâm thu."}, {"label": "Atropine 0.5 mg", "next": "end_partial", "points": 0, "feedback": "⚠ Atropine không còn được khuyến cáo cho vô tâm thu trong các phác đồ mới."}]}]'::jsonb, '{"end_good": {"title": "🎉 Cứu sống bệnh nhân!", "msg": "Bạn xử trí ngừng tim trong PT đúng phác đồ ALS. Ép tim chất lượng + adrenalin đúng thời điểm là chìa khóa. +70 XP."}, "end_partial": {"title": "💪 Hiểu chưa đủ cập nhật", "msg": "Atropine đã được loại khỏi phác đồ ngừng tim/vô tâm thu - cần cập nhật ALS mới nhất. +10 XP."}, "end_bad": {"title": "⚠ Phân biệt nhịp sai", "msg": "Vô tâm thu = không có hoạt động điện - sốc điện vô ích và lãng phí thời gian. Cần ôn lại ''shockable vs non-shockable rhythm''."}, "bad1": {"title": "❌ Trì hoãn vàng", "msg": "Mỗi 1 phút không CPR = giảm 7-10% cơ hội sống. Bắt đầu CPR ngay khi xác nhận ngừng tim."}, "bad2": {"title": "❌ Sai phác đồ", "msg": "Ngừng tim cần CPR + thuốc cấp cứu, không phải an thần."}, "bad3": {"title": "❌ Tần số không đủ", "msg": "AHA khuyến cáo 100-120/phút - nghe nhịp ''Stayin Alive'' để giữ nhịp."}, "bad4": {"title": "❌ Quá nhanh", "msg": "Trên 120/phút giảm hiệu quả vì thất không kịp đổ đầy."}}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO scenarios (id, title, intro, skill_id, tt32_tag, steps, endings) VALUES ('SC05', 'Tình huống: Tổn thương niệu đạo khi đặt sonde', 'Bạn đang đặt sonde Foley cho bệnh nhân nam sau mổ. Đẩy sonde gặp sức cản. Cố đẩy thêm thì BN kêu đau dữ dội. Sau đó thấy máu đỏ tươi nhỏ giọt từ niệu đạo.', 'S3.7', '', '[{"id": "s1", "prompt": "Hành động đầu tiên?", "options": [{"label": "DỪNG đặt sonde, không cố đẩy thêm, báo BS ngay", "next": "s2", "points": 15, "feedback": "✓ Đúng. Chảy máu khi gặp cản = nghi tổn thương niệu đạo - dừng ngay."}, {"label": "Cố đẩy mạnh hơn để ''qua chỗ hẹp''", "next": "bad1", "points": -30, "feedback": "❌ Có thể tạo đường giả (false passage) gây tổn thương vĩnh viễn."}, {"label": "Rút ra rồi đặt lại với sonde to hơn", "next": "bad2", "points": -25, "feedback": "❌ Sonde to hơn không giải quyết - thậm chí nặng thêm tổn thương."}]}, {"id": "s2", "prompt": "Trong khi chờ BS, làm gì?", "options": [{"label": "Ép vùng tầng sinh môn cầm máu nhẹ, theo dõi sinh hiệu, ghi nhận lượng máu mất", "next": "s3", "points": 15, "feedback": "✓ Đúng. Cầm máu, theo dõi, chuẩn bị hội chẩn niệu khoa."}, {"label": "Thử đặt lại bằng sonde nhỏ hơn", "next": "bad3", "points": -20, "feedback": "❌ Không tự đặt lại khi đã nghi tổn thương - cần BS chuyên khoa."}, {"label": "Cho thuốc giảm đau rồi đặt tiếp", "next": "bad4", "points": -25, "feedback": "❌ Giảm đau che dấu hiệu, đặt tiếp = tổn thương nặng hơn."}]}, {"id": "s3", "prompt": "Ghi chép & phòng ngừa lần sau?", "options": [{"label": "Ghi rõ: thời điểm, sức cản gặp ở vị trí, lượng máu, hội chẩn niệu khoa - cập nhật bảng kiểm", "next": "end_good", "points": 20, "feedback": "✓ Hoàn hảo. Ghi chép chi tiết là cốt lõi của an toàn người bệnh."}, {"label": "Chỉ ghi ''đặt sonde không thuận lợi''", "next": "end_partial", "points": 5, "feedback": "⚠ Chưa đủ - cần ghi chi tiết để phục vụ điều trị tiếp theo."}, {"label": "Không cần ghi vì đã báo BS", "next": "end_bad", "points": -15, "feedback": "❌ Mọi sự cố y khoa phải được ghi chép - nghĩa vụ pháp lý."}]}]'::jsonb, '{"end_good": {"title": "🎉 Xử lý đúng quy trình!", "msg": "Bạn đã dừng kịp thời, cầm máu, hội chẩn và ghi chép đầy đủ. An toàn NB là tối thượng. +50 XP."}, "end_partial": {"title": "💪 Đúng nhưng chưa đầy đủ", "msg": "Cần ôn lại quy chuẩn ghi chép sự cố y khoa. +20 XP."}, "end_bad": {"title": "⚠ Sai sót pháp lý", "msg": "Không ghi chép đầy đủ là vi phạm quy định KCB. Có thể gây hậu quả pháp lý."}, "bad1": {"title": "❌ Hành động nguy hiểm", "msg": "Đẩy mạnh khi gặp cản tạo đường giả, có thể tổn thương vĩnh viễn niệu đạo."}, "bad2": {"title": "❌ Sai cơ bản", "msg": "Sonde to hơn KHÔNG giúp - cần đánh giá nguyên nhân trước."}, "bad3": {"title": "❌ Vượt thẩm quyền", "msg": "Khi nghi tổn thương niệu đạo - cần BS niệu khoa, không tự đặt lại."}, "bad4": {"title": "❌ Che dấu hiệu", "msg": "Giảm đau làm mất khả năng phản hồi của BN, dễ gây tổn thương nặng hơn."}}'::jsonb) ON CONFLICT (id) DO NOTHING;
